import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';
import { useToast } from '../components/ui/Toast';

export default function AccountPage() {
  const { user, supabase, isPremium, isLoading, invokeEdgeFunction, signOut } = useAuth();
  const brand = useBrand();
  const { showToast } = useToast();
  const navigate = useNavigate();
  const [profile, setProfile] = useState<Record<string, unknown> | null>(null);

  useEffect(() => {
    if (isLoading) return;
    if (!user) { navigate('/login'); return; }

    async function load() {
      const { data } = await supabase
        .from('user_profiles')
        .select('*')
        .eq('user_id', user!.id)
        .maybeSingle();
      setProfile(data);
    }
    load();
  }, [user, supabase, isLoading, navigate]);

  async function handleBillingPortal() {
    const { data, error } = await invokeEdgeFunction('create-portal-session', {
      returnUrl: window.location.href,
    });
    if (error) { showToast(error.message, true); return; }
    const url = (data as Record<string, string>)?.url;
    if (url) window.location.href = url;
  }

  async function handleDeleteAccount() {
    if (!confirm('Are you sure you want to delete your account? This cannot be undone.')) return;
    const { error } = await invokeEdgeFunction('delete-account', {});
    if (error) { showToast(error.message, true); return; }
    await signOut();
    navigate('/');
  }

  if (isLoading || !user) return null;

  const name = user.user_metadata?.full_name || user.email || '';
  const avatar = user.user_metadata?.avatar_url
    || `https://ui-avatars.com/api/?background=random&name=${encodeURIComponent(user.email || '')}`;

  return (
    <div className="account-wrap" style={{ maxWidth: '600px', margin: '0 auto', padding: '2rem 1.5rem' }}>
      <h1 style={{ fontSize: '1.5rem', marginBottom: '2rem', color: 'var(--text-primary)' }}>Account</h1>

      {/* Profile Card */}
      <div className="account-section glass-panel" style={{ padding: '1.5rem', marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '1rem' }}>
        <img
          src={avatar}
          alt={name}
          className="profile-avatar"
          style={{ width: '56px', height: '56px', borderRadius: '50%', border: '3px solid var(--primary-color)' }}
        />
        <div>
          <div style={{ fontWeight: 600, fontSize: '1rem', color: 'var(--text-primary)' }}>{name}</div>
          <div className="profile-email" style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>{user.email}</div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', marginTop: '0.25rem' }}>
            {isPremium ? (
              <span className="small-btn" style={{ background: 'rgba(245,158,11,0.15)', color: '#f59e0b', border: 'none' }}>
                <i className="fa-solid fa-crown" /> Pro
              </span>
            ) : (
              <span className="small-btn" style={{ background: 'rgba(139,92,246,0.15)', color: '#8b5cf6', border: 'none' }}>
                Free Plan
              </span>
            )}
          </div>
        </div>
      </div>

      {/* Subscription */}
      <div className="account-section glass-panel" style={{ padding: '1.5rem', marginBottom: '1.5rem' }}>
        <h2 className="section-title" style={{ fontSize: '1rem', marginBottom: '1rem' }}>Subscription</h2>
        {isPremium ? (
          <>
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', marginBottom: '1rem' }}>
              You have unlimited access to all 26 AI tools.
            </p>
            <button onClick={handleBillingPortal} className="btn ghost-btn">
              <i className="fa-solid fa-credit-card" /> Manage Billing
            </button>
          </>
        ) : (
          <>
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', marginBottom: '1rem' }}>
              2 free resume tailors/month + 1 free try of each tool.
            </p>
            <button
              onClick={() => navigate('/pricing')}
              className="btn secondary-btn"
              style={{ background: 'linear-gradient(135deg, #f59e0b, #d97706)', color: '#fff', border: 'none' }}
            >
              <i className="fa-solid fa-crown" /> Upgrade to Pro — $9.99/mo
            </button>
          </>
        )}
      </div>

      {/* News Briefing Preferences */}
      <div className="account-section glass-panel" style={{ padding: '1.5rem', marginBottom: '1.5rem' }}>
        <h2 className="section-title" style={{ fontSize: '1rem', marginBottom: '1rem' }}>News Briefing</h2>
        <p style={{ color: 'var(--text-secondary)', fontSize: '0.82rem', marginBottom: '1rem' }}>
          How often would you like to receive your AI-curated news briefing?
        </p>
        <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
          {(['daily', 'weekly', 'off'] as const).map(freq => {
            const current = (profile?.briefing_frequency as string) || 'daily';
            const isActive = current === freq;
            return (
              <button
                key={freq}
                className={`btn ${isActive ? 'secondary-btn' : 'ghost-btn'}`}
                onClick={async () => {
                  await supabase.from('user_profiles').update({ briefing_frequency: freq }).eq('user_id', user.id);
                  setProfile(prev => prev ? { ...prev, briefing_frequency: freq } : prev);
                  showToast(`Briefing frequency set to ${freq}`);
                }}
              >
                {freq === 'daily' && <><i className="fa-solid fa-calendar-day" /> Daily</>}
                {freq === 'weekly' && <><i className="fa-solid fa-calendar-week" /> Weekly</>}
                {freq === 'off' && <><i className="fa-solid fa-bell-slash" /> Off</>}
              </button>
            );
          })}
        </div>
      </div>

      {/* Danger Zone */}
      <div className="account-section glass-panel" style={{ padding: '1.5rem', borderColor: 'rgba(239,68,68,0.3)' }}>
        <h2 className="section-title" style={{ fontSize: '1rem', marginBottom: '0.5rem', color: '#ef4444' }}>Danger Zone</h2>
        <p style={{ color: 'var(--text-secondary)', fontSize: '0.82rem', marginBottom: '1rem' }}>
          Permanently delete your account and all data. This cannot be undone.
        </p>
        <button
          onClick={handleDeleteAccount}
          className="btn ghost-btn"
          style={{ border: '1px solid #ef4444', color: '#ef4444' }}
        >
          <i className="fa-solid fa-trash" /> Delete Account
        </button>
      </div>
    </div>
  );
}
